var init={init:function(){$(".post_content").lightGallery({selector:".c_gallery_link",width:"960px",controls:true,download:false,counter:false});$(".c_tooltip").popover({placement:"right",trigger:"hover",html:true});$(".c_tooltip_bottom").popover({placement:"bottom",trigger:"hover",html:true});$(".c_tooltip_top").popover({placement:"top",trigger:"hover",html:true});$("#i_button_karma_clear").click(function(){$("#i_karma_clear").modal()})},getPage:function(a){$.ajax({url:"/"+a,type:"post",dataType:"json",data:{action:"getPage"},beforeSend:function(){$("#page_dialog").modal();$("#page_dialog_progress").show()},success:function(b){$("#page_dialog_label").html(b.page.title);$("#page_dialog_data").html('<div style="position: relative">'+b.page.text+"</div>")},complete:function(){$("#page_dialog_progress").hide()},error:function(){$("#page_dialog_error").addClass("alert alert-danger").html("Не удалось выполнить запрос")}})}};$(document).ready(function(){init.init()});function number_format(d,b,k,c){var f,e,h,g,a;if(isNaN(b=Math.abs(b))){b=2}if(k==undefined){k=","}if(c==undefined){c="."}f=parseInt(d=(+d||0).toFixed(b))+"";if((e=f.length)>3){e=e%3}else{e=0}a=(e?f.substr(0,e)+c:"");h=f.substr(e).replace(/(\d{3})(?=\d)/g,"$1"+c);g=(b?k+Math.abs(d-f).toFixed(b).replace(/-/,0).slice(2):"");return a+h+g};